    function fnFavorite(_this){

    	const formData = new FormData();
    	formData.append('searchSyr', $(_this).data('searchsyr'));
        formData.append('unvCd', $(_this).data('unvcd'));
        formData.append('slcnGroupCd', $(_this).data('slcngroupcd'));
        formData.append('rcmtMmntCd', $(_this).data('rcmtmmntcd'));
        formData.append('ruCd', $(_this).data('rucd'));
        formData.append('ruSn', $(_this).data('rusn'));
        formData.append('lclsfAftCd', $(_this).data('lclsfaftcd'));
        formData.append('taskSrvcCd', 'KCU');
        formData.append('_csrf', $("meta[name='_csrf']").attr("content"));

		var userId = $('input[name=userId]:checked').val();
		if(userId) {
			formData.append('userId', userId); // 입학도우미에서 사용
		}

		const favoriteKey = `${$(_this).data('unvcd')}-${$(_this).data('comscsbjtcd')}-${$(_this).data('rucd')}-${$(_this).data('rusn')}`;
		const isChecked = $(_this).is(':checked');	

		$('input[data-key='+favoriteKey+']').each(function(){ 
			this.checked = isChecked;
        });

		if (isChecked) {

            // 나의 관심 전형 등록
            fn_axios.post(
                '/ucp/prc/uni/admssFavoriteSave.do'
                , formData
                , function(fragment){   
                	alert('관심전형에 등록되었습니다.');
                	$(_this).attr('checked', true);
                	fnFavoriteStarChg(_this);
                }
            );

        }else{

            // 나의 관심 전형 삭제
            fn_axios.post(
                '/ucp/prc/uni/admssFavoriteRemove.do'
                , formData
                , function(fragment){
                	alert('관심전형 등록이 해제되었습니다.');
                	$(_this).attr('checked', false);
                	fnFavoriteStarChg(_this);
                }
            );
        }
    }

