/* 240910 AI 추천 추가 - 성적분석(정시) 셀렉트  */
$(document).on('click', '.aiListTitleRight .aiSelectCon button', function() {

	let bottomSel = $(this).offset().top + $(this).outerHeight();
	let dropDown = $(this).parent('.aiSelectIcon').next('.regularTestCaseOpt');

	if ($(dropDown).is(":visible")){
		$('.regularTestCaseOpt').hide();
		$('.aiSelectIcon').removeClass("on");
	} else {
		$('.regularTestCaseOpt').hide();
		$('.aiSelectIcon').removeClass("on");
		if ((bottomSel + $(dropDown).height()) > $(".popupContArea").height()) {
			$(dropDown).css('top', $(dropDown).height() - 74);
		} else {
			$(dropDown).css('top', 48);
		}
		$(this).parent('.aiSelectIcon').addClass("on");
		$(this).parent('.aiSelectIcon').next('.regularTestCaseOpt').show();
	}

	if ($(this).parent('.aiSelectIcon').hasClass('on')) {
		$(this).parent('.aiSelectIcon').css('border', 'solid 1px #111');
		$('.aiSelectIcon .selCustBtn img').css('transform', 'translate(0, -50%) rotate(180deg)');
	} else {
		$(this).parent('.aiSelectIcon').css('border', 'solid 1px #ccc'); 
		$('.aiSelectIcon .selCustBtn img').css('transform', 'translate(0, -50%) rotate(0deg)');
	}
})

/* 수능/모의고사 콤보박스 변경 시 */
function fnSelTypeNmSet(element, value, value2) { 
	const hiddenInput = element.parentElement.parentElement.querySelector('input:nth-of-type(1)'); 
	hiddenInput.value = value; 

	const hiddenInput2 = element.parentElement.parentElement.querySelector('input:nth-of-type(2)'); 
	hiddenInput2.value = value2; 

	const selCustBtn = element.parentElement.parentElement.parentElement.parentElement.querySelector('.selCustBtn'); 
	const img = selCustBtn.querySelector('img'); 

	const aTag = element.querySelector('a');
	const aTagContent = aTag.innerHTML;

	const tempDiv = document.createElement('div');
	tempDiv.innerHTML = aTagContent;
	const span = tempDiv.querySelector('span');
	if (span) {
		span.remove(); 
	}

	const newText = tempDiv.innerHTML;

	selCustBtn.innerHTML = `${newText}${img.outerHTML}`;

	const regularTestCaseOpt = element.parentElement.parentElement.parentElement.parentElement.querySelector('.regularTestCaseOpt'); 
	regularTestCaseOpt.style.display = 'none'; 
	regularTestCaseOpt.parentElement.classList.remove('on'); 
	$('.aiSelectIcon .selCustBtn img').css('transform', 'translate(0, -50%) rotate(0deg)');
}

/* AI 추천 보기 버튼 클릭 시 */ 
function fnAIAdvice() {

	if(($('#catListYn').val() == 'N') && ($('#hsclTypeExistYn').val() == 'Y')){
		$("#popWriteRecordGuide").addClass("on");
		return;
	} else {
		var ncxmMtstTestDayId = $("#ncxmMtstTestDayId").val();

		var formData = new FormData();
		formData.append("aiDmndMenuId", $("#aiMenuId").val());

		if(ncxmMtstTestDayId){ 
			formData.append("ncxmMtstTestDayId", ncxmMtstTestDayId);
		}
		if($("#ncxmMtstTestDayIdNm").val()){ 
			formData.append("ncxmMtstTestDayIdNm", $("#ncxmMtstTestDayIdNm").val());
		}

		fn_axios.post( 
			"/ais/rcd/sco/aisRcdScoRdAjax.do"
			, formData
			, function(fragment){      
				$('#aiFloating').remove();    
				$('#aiRcdScoRdList').replaceWith(fragment);

				//AI추천 후 스크롤 이동
				var element = document.getElementById("aiContent");
				var elementPosition = element.offsetTop; // 요소의 상단 위치
				var marginTop = 70; //상단메뉴고정때문에 마진주어 상단위치 조정

				// 부드럽게 스크롤하는 코드
				window.scrollTo({
					top: elementPosition - marginTop,
					behavior: 'smooth' // 스크롤이 부드럽게 이동하게 함
				});

				var swiperLength = $("#swiperLength").val();
				if(swiperLength > 0){
					const regular_swiper = new Swiper(".main_regular_swiper", {
						loop: true,
						watchSlidesProgress: true,
						spaceBetween: 20,
						pagination: {
							type: 'fraction',
							el: ".aiAdviseRegular .reMoreBtnPage",
							clickable: true,
						},
					});
					document.querySelector('.aiAdviseRegular .reMoreBtn').addEventListener('click', function() {
						regular_swiper.slideNext();
					});
				}
			} 
			, {'showLoading' : true} 
		); 
	}

} 

